input.command:
for f in $(find /app -type f); do 
  n=$(grep -aoc 'W54' "$f"); m=$(grep -aoc '8XD' "$f"); 
  echo "$f  8XD=$m W54=$n"; 
done
echo "=== search all files for full pattern 8XD..W54 (23) ==="; 
for f in $(find /app -type f); do grep -aoE '8XD[A-Z0-9]{17}W54' "$f" | sed 's/./& /g'; done
echo "=== file types of .bin ==="; for f in $(find /app -name '*.bin'); do echo "$f: $(file -b $f), $(wc -c <$f) bytes"; done

cat > /tmp/rec.c <<'EOF'
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

static uint32_t crctab[256];
static void mkcrc(void){
  for(uint32_t i=0;i<256;i++){uint32_t c=i;for(int k=0;k<8;k++)c=(c&1)?(0xEDB88320u^(c>>1)):(c>>1);crctab[i]=c;}
}
static uint32_t crc32(const uint8_t*b,int n){
  uint32_t c=0xFFFFFFFFu;for(int i=0;i<n;i++)c=crctab[(c^b[i])&0xff]^(c>>8);return c^0xFFFFFFFFu;
}

static const char CS[]="0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"; // 36

int main(void){
  mkcrc();
  uint8_t rec[33];
  memcpy(rec,"PASSWORD=8XDP5Q2RT9Z",20);      // bytes 0..19
  for(int i=20;i<29;i++)rec[i]=0;              // unknown -> 0
  rec[29]='W';rec[30]='5';rec[31]='4';rec[32]='\n';
  // sanity: corrupted-tail CRC check
  uint8_t corr[33]; memcpy(corr,rec,33);
  uint8_t ct[13]={0x17,0x2a,0xab,0x9e,0x2f,0xae,0xed,0xeb,0x29,0xa1,0x2e,0x0f,0x9d};
  memcpy(corr+20,ct,13);
  fprintf(stderr,"corrupted CRC=%08x (unzip said 4e5bfc80)\n",crc32(corr,33));

  uint32_t base=crc32(rec,33);
  uint32_t target=0xb0725dc4u;
  uint32_t G=target^base;
  // T[pos 0..8][charset 0..35]
  static uint32_t T[9][36];
  for(int p=0;p<9;p++)for(int j=0;j<36;j++){uint8_t s[33];memcpy(s,rec,33);s[20+p]=(uint8_t)CS[j];T[p][j]=crc32(s,33)^base;}

  // A = positions 0..3 (36^4), B = positions 4..8 (36^5)
  long NA=36L*36*36*36;
  typedef struct{uint32_t key;uint32_t idx;}E;
  E*arr=malloc(sizeof(E)*NA);
  long ai=0;
  for(int a0=0;a0<36;a0++){uint32_t x0=T[0][a0];
   for(int a1=0;a1<36;a1++){uint32_t x1=x0^T[1][a1];
    for(int a2=0;a2<36;a2++){uint32_t x2=x1^T[2][a2];
     for(int a3=0;a3<36;a3++){uint32_t x3=x2^T[3][a3];
      arr[ai].key=x3; arr[ai].idx=((a0*36+a1)*36+a2)*36+a3; ai++;
   }}}}
  // sort by key
  int cmp(const void*p,const void*q){uint32_t a=((E*)p)->key,b=((E*)q)->key;return a<b?-1:a>b?1:0;}
  qsort(arr,NA,sizeof(E),cmp);

  FILE*out=fopen("/app/recovered_passwords.txt","w");
  long found=0;
  for(int b0=0;b0<36;b0++){uint32_t y0=T[4][b0];
   for(int b1=0;b1<36;b1++){uint32_t y1=y0^T[5][b1];
    for(int b2=0;b2<36;b2++){uint32_t y2=y1^T[6][b2];
     for(int b3=0;b3<36;b3++){uint32_t y3=y2^T[7][b3];
      for(int b4=0;b4<36;b4++){uint32_t need=G^(y3^T[8][b4]);
        // binary search need in arr
        long lo=0,hi=NA-1,mid,pos=-1;
        while(lo<=hi){mid=(lo+hi)>>1;if(arr[mid].key<need)lo=mid+1;else if(arr[mid].key>need)hi=mid-1;else{pos=mid;break;}}
        if(pos<0)continue;
        // scan neighbours with equal key
        long s=pos; while(s>0&&arr[s-1].key==need)s--;
        for(long k=s;k<NA&&arr[k].key==need;k++){
          uint32_t idx=arr[k].idx;
          int a3=idx%36;idx/=36;int a2=idx%36;idx/=36;int a1=idx%36;idx/=36;int a0=idx;
          char pw[24];
          memcpy(pw,"8XDP5Q2RT9Z",11);
          pw[11]=CS[a0];pw[12]=CS[a1];pw[13]=CS[a2];pw[14]=CS[a3];
          pw[15]=CS[b0];pw[16]=CS[b1];pw[17]=CS[b2];pw[18]=CS[b3];pw[19]=CS[b4];
          pw[20]='W';pw[21]='5';pw[22]='4';pw[23]=0;
          fprintf(out,"%s\n",pw); found++;
        }
   }}}}}
  fclose(out);
  fprintf(stderr,"found=%ld  (est %.0f)\n",found,(double)NA*36*36*36*36*36/4294967296.0);
  return 0;
}
EOF
cc -O2 -o /tmp/rec /tmp/rec.c 2>&1 | head; echo "compiled"; time /tmp/rec
